PARAMETERS __เลขที่ใบเบิก Long;
SELECT DISTINCTROW *
FROM [SELECT [สินค้าในแต่ละใบเบิก].*, [สินค้า].[หน่วยนับ], [สินค้าในแต่ละใบเบิก].[หมายเหตุ] FROM สินค้า INNER JOIN สินค้าในแต่ละใบเบิก ON [สินค้า].[สินค้า] = [สินค้าในแต่ละใบเบิก].[สินค้า]]. AS [frm เบิกสินค้า]
WHERE ([__เลขที่ใบเบิก] = [เลขที่ใบเบิก]);

PARAMETERS __เลขที่ใบรับเข้า Value;
SELECT DISTINCTROW *
FROM [SELECT [สินค้าในแต่ละใบรับเข้า].[สินค้า], [สินค้าในแต่ละใบรับเข้า].[จำนวนรับเข้า], [สินค้า].[หน่วยนับ], [สินค้าในแต่ละใบรับเข้า].[เลขที่ใบรับเข้า], [สินค้าในแต่ละใบรับเข้า].[หมายเลขกล่อง], [สินค้า].[รหัสสินค้า] FROM สินค้า INNER JOIN สินค้าในแต่ละใบรับเข้า ON [สินค้า].[สินค้า] = [สินค้าในแต่ละใบรับเข้า].[สินค้า]]. AS [frm รับเข้าสินค้า]
WHERE ([__เลขที่ใบรับเข้า] = [เลขที่ใบรับเข้า]);

PARAMETERS __เลขที่ออเดอร์ Value;
SELECT DISTINCTROW *
FROM [SELECT [รายละเอียดออเดอร์].[เลขที่ออเดอร์], [qry สินค้าในแต่ละออเดอร์ร้านค้า].[สินค้า], [qry สต็อคสินค้า].Expr1 FROM (รายละเอียดออเดอร์ INNER JOIN [qry สินค้าในแต่ละออเดอร์ร้านค้า] ON [รายละเอียดออเดอร์].[เลขที่ออเดอร์] = [qry สินค้าในแต่ละออเดอร์ร้านค้า].[เลขที่ออเดอร์]) INNER JOIN [qry สต็อคสินค้า] ON [qry สินค้าในแต่ละออเดอร์ร้านค้า].[สินค้า] = [qry สต็อคสินค้า].[สินค้า].[สินค้า] ORDER BY [qry สินค้าในแต่ละออเดอร์ร้านค้า].[สินค้า]]. AS frm_salesorder_fishingshop
WHERE ([__เลขที่ออเดอร์] = [เลขที่ออเดอร์]);

PARAMETERS __เลขที่ออเดอร์ Value;
SELECT DISTINCTROW *
FROM [qry สต็อคสินค้าในแต่ละออเดอร์ปลีก] AS frm_salesorder_retail
WHERE ([__เลขที่ออเดอร์] = [เลขที่ออเดอร์]);

PARAMETERS __เลขที่ออเดอร์ Value;
SELECT DISTINCTROW *
FROM [qry สินค้าในแต่ละออเดอร์ปลีก] AS frm_salesorder_retail
WHERE ([__เลขที่ออเดอร์] = [เลขที่ออเดอร์]);

PARAMETERS __หมายเลขสมาชิก Value;
SELECT DISTINCTROW *
FROM [qry คะแนนรวมลูกค้าแต่ละคน] AS [รายละเอียดออเดอร์]
WHERE ([__หมายเลขสมาชิก] = [หมายเลขสมาชิก]);

PARAMETERS __เลขที่ออเดอร์ Value;
SELECT DISTINCTROW *
FROM [สินค้าในแต่ละออเดอร์] AS [รายละเอียดออเดอร์1]
WHERE ([__เลขที่ออเดอร์] = [เลขที่ออเดอร์]);

SELECT [รายละเอียดออเดอร์].[เลขที่ออเดอร์], [รายละเอียดออเดอร์].[ช่องทางสั่งซื้อ], [รายละเอียดออเดอร์].[วันที่], [รายละเอียดออเดอร์].[พนักงานรับออเดอร์], [รายละเอียดออเดอร์].[ส่วนลดท้ายบิล(%)], [ข้อมูลร้านค้า].[ชื่อร้าน], [ข้อมูลร้านค้า].[เบอร์โทรศัพท์ร้านค้า], [ข้อมูลร้านค้า].[วันหยุด], [ข้อมูลร้านค้า].[ขนส่งที่สะดวก], [ข้อมูลร้านค้า].[ที่อยู่], [สินค้าในแต่ละออเดอร์].[สินค้า], [สินค้าในแต่ละออเดอร์].[จำนวน], [สินค้า].[หน่วยนับ], [สินค้า].[ราคาก่อนแวท], [สินค้า].[ส่วนลดร้านค้าก่อนแวท], [ราคาก่อนแวท]-[ส่วนลดร้านค้าก่อนแวท] AS [ราคาหลังหักส่วนลดร้านค้า], [ราคาหลังหักส่วนลดร้านค้า]*[จำนวน] AS [ราคารวมหลังหักส่วนลดร้านค้า], [รายละเอียดออเดอร์].[หมายเหตุอื่นๆ], [ข้อมูลร้านค้า].[รหัสร้านค้า], [ข้อมูลร้านค้า].[หมายเหตุเฉพาะร้าน], [รายละเอียดออเดอร์].[เลขที่invoiceของแต่ละเดือน], [รายละเอียดออเดอร์].[เลขที่invoiceของปี], [ข้อมูลร้านค้า].[ชื่อร้านสำหรับออกใบกำกับ], [ข้อมูลร้านค้า].[ที่อยู่สำหรับออกใบกำกับ], [ข้อมูลร้านค้า].[เลขประจำตัวผู้เสียภาษีร้านค้า], [สินค้า].[รหัสสินค้า], [รายละเอียดออเดอร์].[วันที่โอนเงิน], [รายละเอียดออเดอร์].[วันที่inv]
FROM [สินค้า] INNER JOIN (([ข้อมูลร้านค้า] INNER JOIN [รายละเอียดออเดอร์] ON [ข้อมูลร้านค้า].[รหัสร้านค้า] = [รายละเอียดออเดอร์].[รหัสร้านค้า]) INNER JOIN [สินค้าในแต่ละออเดอร์] ON [รายละเอียดออเดอร์].[เลขที่ออเดอร์] = [สินค้าในแต่ละออเดอร์].[เลขที่ออเดอร์]) ON [สินค้า].[สินค้า] = [สินค้าในแต่ละออเดอร์].[สินค้า]
WHERE ((([รายละเอียดออเดอร์].[เลขที่ออเดอร์])=[Forms]![frm_salesorder_fishingshop]![เลขที่ออเดอร์]));

SELECT [รายละเอียดออเดอร์].[เลขที่ออเดอร์], [รายละเอียดออเดอร์].[ช่องทางสั่งซื้อ], [รายละเอียดออเดอร์].[วันที่], [รายละเอียดออเดอร์].[พนักงานรับออเดอร์], [รายละเอียดออเดอร์].[ส่วนลดท้ายบิล(%)], [ข้อมูลร้านค้า].[ชื่อร้าน], [ข้อมูลร้านค้า].[เบอร์โทรศัพท์ร้านค้า], [ข้อมูลร้านค้า].[วันหยุด], [ข้อมูลร้านค้า].[ขนส่งที่สะดวก], [ข้อมูลร้านค้า].[ที่อยู่], [สินค้าในแต่ละออเดอร์].[สินค้า], [สินค้าในแต่ละออเดอร์].[จำนวน], [สินค้า].[หน่วยนับ], [สินค้า].ราคา, [สินค้า].[ส่วนลดร้านค้า], [ราคา]-[ส่วนลดร้านค้า] AS [ราคาหลังหักส่วนลดร้านค้า], [ราคาหลังหักส่วนลดร้านค้า]*[จำนวน] AS [ราคารวมหลังหักส่วนลดร้านค้า], [รายละเอียดออเดอร์].[หมายเหตุอื่นๆ], [ข้อมูลร้านค้า].[รหัสร้านค้า], [ข้อมูลร้านค้า].[หมายเหตุเฉพาะร้าน]
FROM [สินค้า] INNER JOIN (([ข้อมูลร้านค้า] INNER JOIN [รายละเอียดออเดอร์] ON [ข้อมูลร้านค้า].[รหัสร้านค้า] = [รายละเอียดออเดอร์].[รหัสร้านค้า]) INNER JOIN [สินค้าในแต่ละออเดอร์] ON [รายละเอียดออเดอร์].[เลขที่ออเดอร์] = [สินค้าในแต่ละออเดอร์].[เลขที่ออเดอร์]) ON [สินค้า].[สินค้า] = [สินค้าในแต่ละออเดอร์].[สินค้า]
WHERE ((([รายละเอียดออเดอร์].[เลขที่ออเดอร์])=[Forms]![frm_salesorder_fishingshop]![เลขที่ออเดอร์]));

