FROM [สินค้า] INNER JOIN (([ข้อมูลร้านค้า] INNER JOIN [รายละเอียดออเดอร์] ON [ข้อมูลร้านค้า].[รหัสร้านค้า] = [รายละเอียดออเดอร์].[รหัสร้านค้า]) INNER JOIN [สินค้าในแต่ละออเดอร์] ON [รายละเอียดออเดอร์].[เลขที่ออเดอร์] = [สินค้าในแต่ละออเดอร์].[เลขที่ออเดอร์]) ON [สินค้า].[สินค้า] = [สินค้าในแต่ละออเดอร์].[สินค้า]
WHERE ((([รายละเอียดออเดอร์].[เลขที่ออเดอร์])=[Forms]![frm_salesorder_fishingshop]![เลขที่ออเดอร์]));

SELECT [qry คะแนนรวมลูกค้าแต่ละคน].[หมายเลขสมาชิก], [qry คะแนนรวมลูกค้าแต่ละคน].SumOfคะแนน, [ข้อมูลสมาชิก].[คะแนนคีย์มือเพิ่มให้], [ข้อมูลสมาชิก].[คะแนนที่ใช้ครั้งที่1], [ข้อมูลสมาชิก].[คะแนนที่ใช้ครั้งที่2], [ข้อมูลสมาชิก].[คะแนนที่ใช้ครั้งที่3], [Sumofคะแนน]+[คะแนนคีย์มือเพิ่มให้]-[คะแนนที่ใช้ครั้งที่1]-[คะแนนที่ใช้ครั้งที่2]-[คะแนนที่ใช้ครั้งที่3] AS Expr1
FROM [qry คะแนนรวมลูกค้าแต่ละคน] INNER JOIN [ข้อมูลสมาชิก] ON [qry คะแนนรวมลูกค้าแต่ละคน].[หมายเลขสมาชิก] = [ข้อมูลสมาชิก].[หมายเลขสมาชิก]
WHERE ((([qry คะแนนรวมลูกค้าแต่ละคน].[หมายเลขสมาชิก])=[Forms]![frm_salesorder_retail]![หมายเลขสมาชิก]));

SELECT [สินค้าในแต่ละออเดอร์].[สินค้า], Sum([สินค้าในแต่ละออเดอร์].[จำนวน]) AS [SumOfจำนวน], [สินค้า].[หน่วยนับ]
